-- Índice composto para verificação de duplicatas (estabelecimento + atendimento + sequencia)
CREATE INDEX IF NOT EXISTS idx_dadosTasy_duplicatas ON dadosTasy (estabelecimentoId, atendimento, sequencia);

-- Índice para busca por estabelecimento e data
CREATE INDEX IF NOT EXISTS idx_dadosTasy_estab_data ON dadosTasy (estabelecimentoId, dataFaturado);

-- Índice para busca por convênio
CREATE INDEX IF NOT EXISTS idx_dadosTasy_convenio ON dadosTasy (estabelecimentoId, convenio(50));

-- Índice para busca por guia
CREATE INDEX IF NOT EXISTS idx_dadosTasy_guia ON dadosTasy (estabelecimentoId, guia);

-- Índice para busca por atendimento
CREATE INDEX IF NOT EXISTS idx_dadosTasy_atendimento ON dadosTasy (atendimento);

-- Índice para importação
CREATE INDEX IF NOT EXISTS idx_dadosTasy_importacao ON dadosTasy (importacaoId);

